#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <sys/wait.h>
#include <sys/types.h>

/*
 * Process Control System Calls Demonstration
 * Category 1: Process Control
 * 
 * System Calls Used:
 * - fork() : Create a new process
 * - exec() : Replace process image (we use execlp)
 * - wait() : Wait for child process to terminate
 * - getpid(): Get current process ID
 * - getppid(): Get parent process ID
 * - exit() : Terminate process
 */

int main() {
 pid_t pid; // Process ID from fork()
 int status; // Status from wait()
 int child_exit_code = 42;

 printf("=== Process Control System Calls Demo ===\n\n");

 // Display parent information using getpid() and getppid()
 printf("Parent Process: PID = %d, Parent PID = %d\n", 
 getpid(), getppid());

 // SYSTEM CALL: fork() - Create child process
 pid = fork();

 if (pid < 0) {
 // fork() failed
 perror("fork failed");
 exit(1);
 }

 if (pid == 0) {
 // CHILD PROCESS (fork returns 0 in child)
 printf("\n[CHILD] I am the child process\n");
 printf("[CHILD] My PID = %d\n", getpid());
 printf("[CHILD] Parent PID = %d\n", getppid());

 // SYSTEM CALL: execlp() - Part of exec() family
 // Replaces current process image with "ls -la"
 printf("[CHILD] Executing 'ls -la' using exec()...\n\n");

 // This replaces the child process with "ls -la"
 // If exec succeeds, this line never executes
 execlp("ls", "ls", "-la", NULL);

 // Only reached if exec fails
 perror("exec failed");
 exit(1); // Abnormal termination (abort)

 } else {
 // PARENT PROCESS (fork returns child's PID)
 printf("\n[PARENT] I am the parent process\n");
 printf("[PARENT] Child process PID = %d\n", pid);

 // SYSTEM CALL: wait() - Wait for child to terminate
 // This suspends parent until child finishes
 printf("[PARENT] Waiting for child to complete...\n");

 pid_t terminated_pid = wait(&status);

 // Check how child terminated
 if (WIFEXITED(status)) {
 // Normal termination via exit()
 printf("\n[PARENT] Child %d exited normally with code: %d\n",
 terminated_pid, WEXITSTATUS(status));
 } else if (WIFSIGNALED(status)) {
 // Killed by signal
 printf("\n[PARENT] Child %d killed by signal: %d\n",
 terminated_pid, WTERMSIG(status));
 }

 printf("\n[PARENT] Parent exiting normally\n");
 }

 return 0;
}

/*
 * COMPILATION: gcc -o process_demo process_demo.c
 * EXECUTION: ./process_demo
 * 
 * Sample Output:
 * === Process Control System Calls Demo ===
 * 
 * Parent Process: PID = 1234, Parent PID = 1200
 * 
 * [PARENT] I am the parent process
 * [PARENT] Child process PID = 1235
 * [PARENT] Waiting for child to complete...
 * 
 * [CHILD] I am the child process
 * [CHILD] My PID = 1235
 * [CHILD] Parent PID = 1234
 * [CHILD] Executing 'ls -la' using exec()...
 * 
 * total 12
 * drwxr-xr-x 1 user user 4096 . ...
 * 
 * [PARENT] Child 1235 exited normally with code: 0
