#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <string.h>
#include <sys/wait.h>

/*
 * Communication System Calls Demonstration
 * Category 5: Communication (IPC - Inter Process Communication)
 * 
 * This program demonstrates:
 * - pipe() : Create a pipe for inter-process communication
 * - fork() : Create processes to communicate
 * - read() : Read from pipe
 * - write() : Write to pipe
 * - close() : Close pipe ends
 * 
 * Architecture: Parent writes to pipe, child reads from pipe
 */

#define BUFFER_SIZE 256
#define READ_END 0
#define WRITE_END 1

int main() {
 int pipefd[2]; // File descriptors for pipe [0]=read, [1]=write
 pid_t pid;
 char write_msg[] = "Hello from parent process via pipe!";
 char read_msg[BUFFER_SIZE];

 printf("=== Communication System Calls Demo (Pipes) ===\n\n");

 // SYSTEM CALL: pipe() - Create an anonymous pipe
 // pipefd[0] = read end, pipefd[1] = write end
 if (pipe(pipefd) == -1) {
 perror("pipe failed");
 exit(1);
 }
 printf("1. pipe() - Created pipe: read_fd=%d, write_fd=%d\n", 
 pipefd[READ_END], pipefd[WRITE_END]);

 // SYSTEM CALL: fork() - Create child process
 pid = fork();

 if (pid < 0) {
 perror("fork failed");
 exit(1);
 }

 if (pid == 0) {
 // CHILD PROCESS - Will READ from pipe

 // Close the write end - child only reads
 close(pipefd[WRITE_END]);
 printf("2. close() - Child closed write end of pipe\n");

 // SYSTEM CALL: read() - Read from pipe
 ssize_t bytes_read = read(pipefd[READ_END], read_msg, BUFFER_SIZE);

 if (bytes_read > 0) {
 read_msg[bytes_read] = '\0'; // Null terminate
 printf("3. read() - Child received: \"%s\"\n", read_msg);
 printf(" Bytes read: %zd\n", bytes_read);
 }

 // Close the read end after reading
 close(pipefd[READ_END]);
 printf("4. close() - Child closed read end of pipe\n");

 exit(0);

 } else {
 // PARENT PROCESS - Will WRITE to pipe

 // Close the read end - parent only writes
 close(pipefd[READ_END]);
 printf("5. close() - Parent closed read end of pipe\n");

 // SYSTEM CALL: write() - Write to pipe
 ssize_t bytes_written = write(pipefd[WRITE_END], 
 write_msg, strlen(write_msg));
 printf("6. write() - Parent sent: \"%s\"\n", write_msg);
 printf(" Bytes written: %zd\n", bytes_written);

 // Close the write end after writing
 close(pipefd[WRITE_END]);
 printf("7. close() - Parent closed write end of pipe\n");

 // Wait for child to complete
 wait(NULL);
 printf("8. wait() - Parent waited for child completion\n");
 }

 printf("\n=== Demo Complete ===\n");
 return 0;
}

/*
 * COMPILATION: gcc -o pipe_demo pipe_demo.c
 * EXECUTION: ./pipe_demo
 * 
 * Expected Output:
 * === Communication System Calls Demo (Pipes) ===
 * 
 * 1. pipe() - Created pipe: read_fd=4, write_fd=5
 * 2. close() - Child closed write end of pipe
 * 5. close() - Parent closed read end of pipe
 * 6. write() - Parent sent: "Hello from parent process via pipe!"
 * Bytes written: 37
 * 7. close() - Parent closed write end of pipe
 * 3. read() - Child received: "Hello from parent process via pipe!"
 * Bytes read: 37
 * 4. close() - Child closed read end of pipe
 * 8. wait() - Parent waited for child completion
 * 
 * === Demo Complete ===
 * 
 * NOTE: Output order may vary due to process scheduling
 */
